// src/services/api.js
import axios from "axios";

// Use environment variable or fallback
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// -------------------------
// Fake Login for testing
// -------------------------
api.login = async (email, password, rememberMe = false) => {
  // Fake login: accept any email/password
  const fakeToken = "fake-jwt-token";

  if (rememberMe) {
    localStorage.setItem("token", fakeToken);
  } else {
    sessionStorage.setItem("token", fakeToken);
  }

  return { data: { token: fakeToken } };
};

// -------------------------
// Signup API
// -------------------------
api.signup = async (email, password) => {
  return api.post("/auth/signup", { email, password });
};

// -------------------------
// Vehicles APIs
// -------------------------
api.getVehicles = async () => {
  const token = localStorage.getItem("token");
  const response = await api.get("/vehicles", {
    headers: { Authorization: `Bearer ${token}` },
  });
  return response.data;
};

api.addVehicle = async (vehicle) => {
  const token = localStorage.getItem("token");
  const response = await api.post("/vehicles", vehicle, {
    headers: { Authorization: `Bearer ${token}` },
  });
  return response.data;
};

// -------------------------
// Routes APIs
// -------------------------
api.optimizeRoute = async (routeRequest) => {
  const token = localStorage.getItem("token");
  const response = await api.post("/routes/optimize", routeRequest, {
    headers: { Authorization: `Bearer ${token}` },
  });
  return response.data;
};

// -------------------------
// Alerts APIs
// -------------------------
api.getAlerts = async () => {
  const token = localStorage.getItem("token");
  const response = await api.get("/alerts", {
    headers: { Authorization: `Bearer ${token}` },
  });
  return response.data;
};

export default api;
